84	// NewMetricsAPIScaler creates a new HTTP scaler
85	func NewMetricsAPIScaler(config *scalersconfig.ScalerConfig, kubeClient client.Client) (Scaler, error) {
86		metricType, err := GetMetricTargetType(config)
87		if err != nil {
88			return nil, fmt.Errorf("error getting scaler metric type: %w", err)
89		}
90	
91		meta, err := parseMetricsAPIMetadata(config)
92		if err != nil {
93			return nil, fmt.Errorf("error parsing metric API metadata: %w", err)
94		}
95	
96		httpClient := kedautil.CreateHTTPClient(config.GlobalHTTPTimeout, meta.UnsafeSsl)
97	
98		// Handle TLS configuration with authentication config
99		if meta.MetricsAPIAuth != nil && meta.MetricsAPIAuth.EnabledTLS() {
100			tlsConfig, err := kedautil.NewTLSConfig(meta.MetricsAPIAuth.Cert, meta.MetricsAPIAuth.Key, meta.MetricsAPIAuth.CA, meta.UnsafeSsl)
101			if err != nil {
102				return nil, err
103			}
104			httpClient.Transport = kedautil.CreateHTTPTransportWithTLSConfig(tlsConfig)
105		}
106	
107		return &metricsAPIScaler{
108			metricType: metricType,
109			metadata:   meta,
110			httpClient: httpClient,
111			kubeClient: kubeClient,
112			logger:     InitializeLogger(config, "metrics_api_scaler"),
113		}, nil
114	}
115	
116	func parseMetricsAPIMetadata(config *scalersconfig.ScalerConfig) (*metricsAPIScalerMetadata, error) {
117		meta := &metricsAPIScalerMetadata{}
118		if err := config.TypedConfig(meta); err != nil {
119			return nil, fmt.Errorf("error parsing metrics API metadata: %w", err)
120		}
121	
122		meta.triggerIndex = config.TriggerIndex
123	
124		// Special validation for targetValue when not used as metric source
125		if meta.TargetValue == 0 && !config.AsMetricSource {
126			return nil, fmt.Errorf("no targetValue given in metadata")
127		}
128	
129		return meta, nil
130	}
