132	// GetValueFromResponse uses provided valueLocation to access the numeric value in provided body using the format specified.
133	func GetValueFromResponse(body []byte, valueLocation string, format APIFormat) (float64, error) {
134		switch format {
135		case PrometheusFormat:
136			return getValueFromPrometheusResponse(body, valueLocation)
137		case JSONFormat:
138			return getValueFromJSONResponse(body, valueLocation)
139		case XMLFormat:
140			return getValueFromXMLResponse(body, valueLocation)
141		case YAMLFormat:
142			return getValueFromYAMLResponse(body, valueLocation)
143		}
144	
145		return 0, fmt.Errorf("format %s not supported", format)
146	}
147	
148	// getValueFromPrometheusResponse uses provided valueLocation to access the numeric value in provided body
149	func getValueFromPrometheusResponse(body []byte, valueLocation string) (float64, error) {
150		matchers, err := parser.ParseMetricSelector(valueLocation)
151		if err != nil {
152			return 0, err
153		}
154		metricName := ""
155		for _, v := range matchers {
156			if v.Name == "__name__" {
157				metricName = v.Value
158			}
159		}
160	
161		// Ensure EOL
162		bodyStr := strings.ReplaceAll(string(body), "\r\n", "\n")
163	
164		// Check if newline is present
165		if len(bodyStr) > 0 && !strings.HasSuffix(bodyStr, "\n") {
166			bodyStr += "\n"
167		}
168	
169		reader := strings.NewReader(bodyStr)
170		familiesParser := expfmt.TextParser{}
171		families, err := familiesParser.TextToMetricFamilies(reader)
172		if err != nil {
173			return 0, fmt.Errorf("prometheus format parsing error: %w", err)
174		}
175	
176		family, ok := families[metricName]
177		if !ok {
178			return 0, fmt.Errorf("metric '%s' not found", metricName)
179		}
180	
181		metrics := family.GetMetric()
182		for _, metric := range metrics {
183			labels := metric.GetLabel()
184			match := true
185			for _, matcher := range matchers {
186				matcherFound := false
187				if matcher == nil {
188					continue
189				}
190				// The name has been already validated,
191				// so we can skip it and check the other labels
192				if matcher.Name == "__name__" {
193					continue
194				}
195				for _, label := range labels {
196					if *label.Name == matcher.Name &&
197						*label.Value == matcher.Value {
198						matcherFound = true
199					}
200				}
201				if !matcherFound {
202					match = false
203				}
204			}
205			if match {
206				untyped := metric.GetUntyped()
207				if untyped != nil && untyped.Value != nil {
208					return *untyped.Value, nil
209				}
210				counter := metric.GetCounter()
211				if counter != nil && counter.Value != nil {
212					return *counter.Value, nil
213				}
214				gauge := metric.GetGauge()
215				if gauge != nil && gauge.Value != nil {
216					return *gauge.Value, nil
217				}
218			}
219		}
220	
221		return 0, fmt.Errorf("value %s not found", valueLocation)
222	}
223	
224	// getValueFromJSONResponse uses provided valueLocation to access the numeric value in provided body using GJSON
225	func getValueFromJSONResponse(body []byte, valueLocation string) (float64, error) {
226		r := gjson.GetBytes(body, valueLocation)
227		if r.Type == gjson.String {
228			v, err := resource.ParseQuantity(r.String())
229			if err != nil {
230				return 0, fmt.Errorf(valueLocationWrongErrorMsg, r.String())
231			}
232			return v.AsApproximateFloat64(), nil
233		}
234		if r.Type != gjson.Number {
235			return 0, fmt.Errorf(valueLocationWrongErrorMsg, r.Type.String())
236		}
237		return r.Num, nil
238	}
239	
240	// getValueFromXMLResponse uses provided valueLocation to access the numeric value in provided body
241	func getValueFromXMLResponse(body []byte, valueLocation string) (float64, error) {
242		var xmlMap map[string]interface{}
243		err := xml.Unmarshal(body, &xmlMap)
244		if err != nil {
245			return 0, err
246		}
247	
248		path, err := kedautil.GetValueByPath(xmlMap, valueLocation)
249		if err != nil {
250			return 0, err
251		}
252	
253		switch v := path.(type) {
254		case int:
255			return float64(v), nil
256		case int64:
257			return float64(v), nil
258		case float64:
259			return v, nil
260		case string:
261			r, err := resource.ParseQuantity(v)
262			if err != nil {
263				return 0, fmt.Errorf(valueLocationWrongErrorMsg, v)
264			}
265			return r.AsApproximateFloat64(), nil
266		default:
267			return 0, fmt.Errorf(valueLocationWrongErrorMsg, v)
268		}
269	}
270	
271	// getValueFromYAMLResponse uses provided valueLocation to access the numeric value in provided body
272	// using generic ketautil.GetValueByPath
273	func getValueFromYAMLResponse(body []byte, valueLocation string) (float64, error) {
274		var yamlMap map[string]interface{}
275		err := yaml.Unmarshal(body, &yamlMap)
276		if err != nil {
277			return 0, err
278		}
279	
280		path, err := kedautil.GetValueByPath(yamlMap, valueLocation)
281		if err != nil {
282			return 0, err
283		}
284	
285		switch v := path.(type) {
286		case int:
287			return float64(v), nil
288		case int64:
289			return float64(v), nil
290		case float64:
291			return v, nil
292		case string:
293			r, err := resource.ParseQuantity(v)
294			if err != nil {
295				return 0, fmt.Errorf(valueLocationWrongErrorMsg, v)
296			}
297			return r.AsApproximateFloat64(), nil
298		default:
299			return 0, fmt.Errorf(valueLocationWrongErrorMsg, v)
300		}
301	}
