373	func (s *metricsAPIScaler) getMetricValue(ctx context.Context) (float64, error) {
374		// if we wish to aggregate metric from a kubernetes service then we need to query each endpoint behind the service
375		if s.metadata.AggregateFromKubeServiceEndpoints {
376			endpointsUrls, err := s.getEndpointsUrlsFromServiceURL(ctx, s.metadata.URL)
377			if err != nil {
378				return 0, fmt.Errorf("failed to get kubernetes endpoints urls from configured service URL")
379			}
380			if len(endpointsUrls) == 0 {
381				return 0, fmt.Errorf("no endpoints URLs were given for the service name")
382			}
383			return s.aggregateMetricsFromMultipleEndpoints(ctx, endpointsUrls)
384		}
385		// get single/unaggregated metric
386		metric, err := s.getMetricValueFromURL(ctx, nil)
387		if err == nil {
388			s.logger.V(1).Info(fmt.Sprintf("fetched single metric from metrics API url : %s. Value is %v\n", s.metadata.URL, metric))
389		}
390		return metric, err
391	}
392	
393	func (s *metricsAPIScaler) aggregateMetricsFromMultipleEndpoints(ctx context.Context, endpointsUrls []string) (float64, error) {
394		// call s.getMetricValueFromURL() for each endpointsUrls in parallel goroutines (maximum 5 at a time) and sum them up
395		const maxGoroutines = 5
396		var mu sync.Mutex
397		sem := semaphore.NewWeighted(maxGoroutines)
398		expectedNbMetrics := len(endpointsUrls)
399		nbErrors := 0
400		var err error
401		var firstMetricEncountered bool
402		var aggregation float64
403		s.logger.V(1).Info(fmt.Sprintf("start iterating %d endpoint urls", len(endpointsUrls)))
404		for _, endpointURL := range endpointsUrls {
405			if err := sem.Acquire(ctx, 1); err != nil {
406				s.logger.Error(err, "Failed to acquire semaphore")
407				continue
408			}
409			go func(url string) {
410				defer sem.Release(1)
411				metric, err := s.getMetricValueFromURL(ctx, &endpointURL)
412	
413				if err != nil {
414					s.logger.V(1).Info(fmt.Sprintf("Error fetching metric for %s: %v\n", url, err))
415					// we will ignore metric for computing aggregation when encountering error : decrease expectedNbMetrics
416					mu.Lock()
417					expectedNbMetrics--
418					nbErrors++
419					mu.Unlock()
420				} else {
421					mu.Lock()
422					switch s.metadata.AggregationType {
423					case MinAggregationType:
424						if !firstMetricEncountered || metric < aggregation {
425							firstMetricEncountered = true
426							aggregation = metric
427						}
428					case MaxAggregationType:
429						if !firstMetricEncountered || metric > aggregation {
430							firstMetricEncountered = true
431							aggregation = metric
432						}
433					default:
434						// sum metrics if we are not looking for min or max value
435						aggregation += metric
436					}
437					mu.Unlock()
438				}
439			}(endpointURL)
440		}
441		// Wait that all goroutines have released their semaphore acquisition
442		if err := sem.Acquire(ctx, maxGoroutines); err != nil {
443			s.logger.V(1).Error(err, "final semaphore acquisition failed")
444		}
445		s.logger.V(1).Info(fmt.Sprintf("ENDED iterating %d endpoint urls, aggregation is now %v", len(endpointsUrls), aggregation))
446	
447		if nbErrors > 0 && nbErrors == len(endpointsUrls) {
448			err = fmt.Errorf("could not get any metric successfully from the %d provided endpoints", len(endpointsUrls))
449		}
450		if s.metadata.AggregationType == AverageAggregationType {
451			aggregation /= float64(expectedNbMetrics)
452		}
453		s.logger.V(1).Info(fmt.Sprintf("fetched %d metrics out of %d endpoints from kubernetes service : %s is %v\n", expectedNbMetrics, len(endpointsUrls), s.metadata.AggregationType, aggregation))
454		return aggregation, err
455	}
456	
457	func (s *metricsAPIScaler) getMetricValueFromURL(ctx context.Context, url *string) (float64, error) {
458		request, err := getMetricAPIServerRequest(ctx, s.metadata, url)
459		if err != nil {
460			return 0, err
461		}
462	
463		r, err := s.httpClient.Do(request)
464		if err != nil {
465			return 0, err
466		}
467		defer r.Body.Close()
468	
469		if r.StatusCode != http.StatusOK {
470			msg := fmt.Sprintf("%s: api returned %d", r.Request.URL.Path, r.StatusCode)
471			return 0, errors.New(msg)
472		}
473	
474		b, err := io.ReadAll(r.Body)
475		if err != nil {
476			return 0, err
477		}
478		v, err := GetValueFromResponse(b, s.metadata.ValueLocation, s.metadata.Format)
479		if err != nil {
480			return 0, err
481		}
482		return v, nil
483	}
484	
485	// Close does nothing in case of metricsAPIScaler
486	func (s *metricsAPIScaler) Close(context.Context) error {
487		if s.httpClient != nil {
488			s.httpClient.CloseIdleConnections()
489		}
490		return nil
491	}
492	
493	// GetMetricSpecForScaling returns the MetricSpec for the Horizontal Pod Autoscaler
494	func (s *metricsAPIScaler) GetMetricSpecForScaling(context.Context) []v2.MetricSpec {
495		externalMetric := &v2.ExternalMetricSource{
496			Metric: v2.MetricIdentifier{
497				Name: GenerateMetricNameWithIndex(s.metadata.triggerIndex, kedautil.NormalizeString(fmt.Sprintf("metric-api-%s", s.metadata.ValueLocation))),
498			},
499			Target: GetMetricTargetMili(s.metricType, s.metadata.TargetValue),
500		}
501		metricSpec := v2.MetricSpec{
502			External: externalMetric, Type: externalMetricType,
503		}
504		return []v2.MetricSpec{metricSpec}
505	}
506	
507	// GetMetricsAndActivity returns value for a supported metric and an error if there is a problem getting the metric
508	func (s *metricsAPIScaler) GetMetricsAndActivity(ctx context.Context, metricName string) ([]external_metrics.ExternalMetricValue, bool, error) {
509		val, err := s.getMetricValue(ctx)
510		if err != nil {
511			return []external_metrics.ExternalMetricValue{}, false, fmt.Errorf("error requesting metrics endpoint: %w", err)
512		}
513	
514		metric := GenerateMetricInMili(metricName, val)
515	
516		return []external_metrics.ExternalMetricValue{metric}, val > s.metadata.ActivationTargetValue, nil
517	}
518	
519	func getMetricAPIServerRequest(ctx context.Context, meta *metricsAPIScalerMetadata, url *string) (*http.Request, error) {
520		var requestURL string
521		if url == nil {
522			url = &meta.URL
523		}
524		// Handle API Key as query parameter if needed
525		if meta.MetricsAPIAuth != nil && meta.MetricsAPIAuth.EnabledAPIKeyAuth() && meta.MetricsAPIAuth.Method == methodValueQuery {
526			url, _ := neturl.Parse(*url)
527			queryString := url.Query()
528			if meta.MetricsAPIAuth.KeyParamName == "" {
529				queryString.Set("api_key", meta.MetricsAPIAuth.APIKey)
530			} else {
531				queryString.Set(meta.MetricsAPIAuth.KeyParamName, meta.MetricsAPIAuth.APIKey)
532			}
533			url.RawQuery = queryString.Encode()
534			requestURL = url.String()
535		} else {
536			requestURL = *url
537		}
538	
539		// Create the request
540		req, err := http.NewRequestWithContext(ctx, "GET", requestURL, nil)
541		if err != nil {
542			return nil, err
543		}
544	
545		// Add API Key as header if needed
546		if meta.MetricsAPIAuth != nil && meta.MetricsAPIAuth.EnabledAPIKeyAuth() && meta.MetricsAPIAuth.Method != methodValueQuery {
547			if meta.MetricsAPIAuth.KeyParamName == "" {
548				req.Header.Add("X-API-KEY", meta.MetricsAPIAuth.APIKey)
549			} else {
550				req.Header.Add(meta.MetricsAPIAuth.KeyParamName, meta.MetricsAPIAuth.APIKey)
551			}
552		}
553	
554		// Add Basic Auth if enabled
555		if meta.MetricsAPIAuth != nil && meta.MetricsAPIAuth.EnabledBasicAuth() {
556			req.SetBasicAuth(meta.MetricsAPIAuth.Username, meta.MetricsAPIAuth.Password)
557		}
558	
559		// Add Bearer token if enabled
560		if meta.MetricsAPIAuth != nil && meta.MetricsAPIAuth.EnabledBearerAuth() {
561			req.Header.Add("Authorization", fmt.Sprintf("Bearer %s", meta.MetricsAPIAuth.BearerToken))
562		}
563	
564		return req, nil
565	}
